-- search_text mirrors production Amazon OpenSearch Service concatenated field

DROP TABLE IF EXISTS anycompany_content;

CREATE TABLE anycompany_content (
    node_id          TEXT PRIMARY KEY,
    internal_id      TEXT,
    external_id      TEXT,
    title            TEXT NOT NULL,
    discipline       TEXT,
    grade_from       INTEGER,
    grade_to         INTEGER,
    language         TEXT DEFAULT 'en',
    content_type     TEXT,
    file_type TEXT,
    media_type       TEXT,
    content_bucket   TEXT,
    standards_alignment TEXT,
    keywords         TEXT,
    isbn_10          TEXT,
    isbn_13          TEXT,
    copyright_year   INTEGER,
    hide_from_student INTEGER DEFAULT 0,
    download         TEXT DEFAULT 'allowed',
    genres           TEXT,
    catalog_group    TEXT,
    cutscore         INTEGER,
    version_state    TEXT,
    version_country  TEXT DEFAULT 'US',
    version_district TEXT,
    search_text      TEXT
);

